UNPATCHED CldSyncConnectRoot (sub_1c0062cc0), both branches validate owner+token:
    if (Feature_565656888__private_IsEnabledDeviceUsage() == 0) {
        // feature disabled: refcount at entry+0x30 keyed first
        if (*(int*)(entry+48) > 0) {
            if (*(entry+96) == arg2 && *entry == arg7) { status = 0; *a8 = entry; }  // owner + token
            else status = STATUS_CLOUD_FILE_NOT_IN_SYNC;  // 0xc000cf09
        } else goto create_new_entry;
    } else {
        // feature enabled: owner field at entry+0x60 keyed first
        if (*(entry+96) == 0) goto create_new_entry;
        if (*(entry+96) == arg2 && *entry == arg7) { ... }  // owner + token
        else status = STATUS_CLOUD_FILE_NOT_IN_SYNC;
    }

PATCHED CldSyncConnectRoot (0x1c0062bd0), equivalent to the unpatched enabled branch:
    if (entry == NULL || *(entry+96) == 0) goto create_new_entry;   // owner field at 0x60
    if (*(entry+96) == arg2 && *entry == arg7) { status = 0; *a8 = entry; }
    else { status = STATUS_CLOUD_FILE_NOT_IN_SYNC; TlmWriteSyncRootAlreadyConnected(); }

UNPATCHED sub_1c0060514, disconnect path:
if (Feature_565656888__private_IsEnabledDeviceUsage() != 0)
    status = CldSyncDisconnectRoot(volume, key, token, &out);      // checks entry+0 == token, else 0xc000cf0b
else
    status = CldSyncDisconnectRootDeprecated(volume, key, &out);   // NO token argument, NO token check

UNPATCHED sub_1c0060514, register path:
if (Feature_565656888__private_IsEnabledDeviceUsage() != 0) {
    FltAcquirePushLockExclusiveEx(a1+96, 0);
    status = CldiPortInsertSyncRootNoLock(a1, key1, key0, token);   // validates owner/token
} else {
    Buffer = { key0, key1 };
    FltAcquirePushLockExclusiveEx(a1+96, 0);
    RtlDeleteElementGenericTableAvl(a1+104, &Buffer);              // per-connection table
    RtlInsertElementGenericTableAvl(a1+104, &Buffer, 0x10, &NewElement);  // NO owner/token check
}

PATCHED sub_1c00604e4:
FltAcquirePushLockExclusiveEx(a1+96, 0);
status = CldiPortInsertSyncRootNoLock(a1, key1, key0, token);       // register: always validated
...
status = CldSyncDisconnectRoot(volume, key, token, &out);          // disconnect: always token-checked

